"""Pydantic field definitions and validators."""
from __future__ import annotations

from typing import Any, Callable, Dict, Iterable, List, Optional, Set, Tuple, Type, Union


class FieldInfo:
    """
    Full field metadata container used internally by Pydantic.

    Holds default value, validators, serializers, and JSON schema metadata.
    """

    def __init__(
        self,
        default: Any = ...,
        *,
        default_factory: Optional[Callable] = None,
        alias: Optional[str] = None,
        alias_priority: Optional[int] = None,
        validation_alias: Optional[Union[str, List]] = None,
        serialization_alias: Optional[str] = None,
        title: Optional[str] = None,
        description: Optional[str] = None,
        examples: Optional[List[Any]] = None,
        exclude: Optional[bool] = None,
        discriminator: Optional[str] = None,
        json_schema_extra: Optional[Dict[str, Any]] = None,
        frozen: Optional[bool] = None,
        validate_default: bool = False,
        repr: bool = True,
        init: Optional[bool] = None,
        init_var: Optional[bool] = None,
        kw_only: Optional[bool] = None,
        pattern: Optional[str] = None,
        strict: Optional[bool] = None,
        gt: Optional[float] = None,
        ge: Optional[float] = None,
        lt: Optional[float] = None,
        le: Optional[float] = None,
        multiple_of: Optional[float] = None,
        allow_inf_nan: Optional[bool] = None,
        max_digits: Optional[int] = None,
        decimal_places: Optional[int] = None,
        min_length: Optional[int] = None,
        max_length: Optional[int] = None,
    ) -> None:
        if default is not ... and default_factory is not None:
            raise ValueError("Cannot specify both 'default' and 'default_factory'")
        self.default = default
        self.default_factory = default_factory
        self.alias = alias
        self.alias_priority = alias_priority
        self.validation_alias = validation_alias
        self.serialization_alias = serialization_alias
        self.title = title
        self.description = description
        self.examples = examples
        self.exclude = exclude
        self.discriminator = discriminator
        self.json_schema_extra = json_schema_extra
        self.frozen = frozen
        self.validate_default = validate_default
        self.repr = repr
        self.metadata: List[Any] = []
        if gt is not None: self.metadata.append(("gt", gt))
        if ge is not None: self.metadata.append(("ge", ge))
        if lt is not None: self.metadata.append(("lt", lt))
        if le is not None: self.metadata.append(("le", le))
        if min_length is not None: self.metadata.append(("min_length", min_length))
        if max_length is not None: self.metadata.append(("max_length", max_length))
        if pattern is not None: self.metadata.append(("pattern", pattern))

    def is_required(self) -> bool:
        return self.default is ... and self.default_factory is None

    def get_default(self) -> Any:
        if self.default_factory is not None:
            return self.default_factory()
        return self.default

    def __repr__(self) -> str:
        parts = [f"default={self.default!r}"]
        if self.alias:
            parts.append(f"alias={self.alias!r}")
        if self.title:
            parts.append(f"title={self.title!r}")
        return f"FieldInfo({', '.join(parts)})"


def Field(
    default: Any = ...,
    *,
    default_factory: Optional[Callable] = None,
    alias: Optional[str] = None,
    title: Optional[str] = None,
    description: Optional[str] = None,
    gt: Optional[float] = None,
    ge: Optional[float] = None,
    lt: Optional[float] = None,
    le: Optional[float] = None,
    min_length: Optional[int] = None,
    max_length: Optional[int] = None,
    pattern: Optional[str] = None,
    examples: Optional[List[Any]] = None,
    **extra: Any,
) -> Any:
    """
    Return a FieldInfo object with the specified constraints.

    Usage::

        class Item(BaseModel):
            name: str = Field(min_length=1, max_length=100, description="Item name")
            price: float = Field(gt=0, description="Price must be positive")
            tags: list[str] = Field(default_factory=list)
    """
    return FieldInfo(
        default=default,
        default_factory=default_factory,
        alias=alias,
        title=title,
        description=description,
        gt=gt, ge=ge, lt=lt, le=le,
        min_length=min_length, max_length=max_length,
        pattern=pattern,
        examples=examples,
    )
